            const scaleX = mainMap.canvas.width / this.canvas.width;
            const scaleY = mainMap.canvas.height / this.canvas.height;
            
            mainMap.syncing = true;
            mainMap.updateUserPosition(userId, x * scaleX, y * scaleY);
